  1→/**
  2→ * Buy Property Services - Custom JavaScript
  3→ * ==========================================
  4→ * Vanilla JS only (no jQuery). All functionality wrapped in DOMContentLoaded.
  5→ * Uses requestAnimationFrame for scroll-based handlers to avoid jank.
  6→ */
  7→
  8→document.addEventListener('DOMContentLoaded', function () {
  9→
 10→  /* ==========================================================================
 11→     1. SCROLL REVEAL ANIMATION
 12→     Uses IntersectionObserver to watch elements with .reveal-on-scroll class.
 13→     When an element enters the viewport (10% visible), it gets the .revealed
 14→     class added, which you can target in CSS for fade-in/slide-up animations.
 15→  ========================================================================== */
 16→
 17→  function initScrollReveal() {
 18→    var revealElements = document.querySelectorAll('.reveal-on-scroll');
 19→    if (!revealElements.length) return;
 20→
 21→    // If IntersectionObserver isn't supported, reveal everything immediately
 22→    if (!('IntersectionObserver' in window)) {
 23→      revealElements.forEach(function (el) {
 24→        el.classList.add('revealed');
 25→      });
 26→      return;
 27→    }
 28→
 29→    var observer = new IntersectionObserver(
 30→      function (entries) {
 31→        entries.forEach(function (entry) {
 32→          if (entry.isIntersecting) {
 33→            entry.target.classList.add('revealed');
 34→            // Stop observing once revealed (animation only happens once)
 35→            observer.unobserve(entry.target);
 36→          }
 37→        });
 38→      },
 39→      { threshold: 0.1 }
 40→    );
 41→
 42→    revealElements.forEach(function (el) {
 43→      // Check if element is already in viewport on page load
 44→      var rect = el.getBoundingClientRect();
 45→      var inViewport =
 46→        rect.top < window.innerHeight &&
 47→        rect.bottom > 0 &&
 48→        rect.left < window.innerWidth &&
 49→        rect.right > 0;
 50→
 51→      if (inViewport) {
 52→        el.classList.add('revealed');
 53→      } else {
 54→        observer.observe(el);
 55→      }
 56→    });
 57→  }
 58→
 59→  initScrollReveal();
 60→
 61→
 62→  /* ==========================================================================
 63→     2. HEADER SCROLL EFFECT
 64→     Adds .header--scrolled class to the site header when the user scrolls
 65→     past 50px. Removes it when they scroll back to the top.
 66→     Uses requestAnimationFrame to throttle the scroll handler.
 67→  ========================================================================== */
 68→
 69→  function initHeaderScroll() {
 70→    var header = document.querySelector('.section-header');
 71→    if (!header) return;
 72→
 73→    var scrollThreshold = 50;
 74→    var ticking = false;
 75→
 76→    function updateHeader() {
 77→      if (window.scrollY > scrollThreshold) {
 78→        header.classList.add('header--scrolled');
 79→      } else {
 80→        header.classList.remove('header--scrolled');
 81→      }
 82→      ticking = false;
 83→    }
 84→
 85→    window.addEventListener('scroll', function () {
 86→      if (!ticking) {
 87→        requestAnimationFrame(updateHeader);
 88→        ticking = true;
 89→      }
 90→    }, { passive: true });
 91→
 92→    // Run once on load in case page is already scrolled (e.g. browser back)
 93→    updateHeader();
 94→  }
 95→
 96→  initHeaderScroll();
 97→
 98→
 99→  /* ==========================================================================
100→     3. SELLING / RENTING TOGGLE
101→     Handles clicks on .hero-toggle-btn buttons (e.g. "Buy" vs "Rent" tabs
102→     on the homepage hero). Adds .active to the clicked button and removes
103→     it from the sibling button. You can extend this later to show/hide
104→     different service category grids.
105→  ========================================================================== */
106→
107→  function initHeroToggle() {
108→    var toggleButtons = document.querySelectorAll('.hero-toggle-btn');
109→    if (!toggleButtons.length) return;
110→
111→    toggleButtons.forEach(function (btn) {
112→      btn.addEventListener('click', function () {
113→        // Remove .active from all sibling toggle buttons
114→        toggleButtons.forEach(function (sibling) {
115→          sibling.classList.remove('active');
116→        });
117→        // Add .active to the clicked button
118→        btn.classList.add('active');
119→
120→        // Future: show/hide service categories based on data attribute
121→        // var category = btn.dataset.category; // e.g. "selling" or "renting"
122→        // document.querySelectorAll('.service-category').forEach(function(cat) {
123→        //   cat.hidden = cat.dataset.category !== category;
124→        // });
125→      });
126→    });
127→  }
128→
129→  initHeroToggle();
130→
131→
132→  /* ==========================================================================
133→     4. SMOOTH SCROLL FOR ANCHOR LINKS
134→     Intercepts clicks on any <a> whose href starts with "#" and smoothly
135→     scrolls to the target element instead of jumping instantly.
136→  ========================================================================== */
137→
138→  function initSmoothScroll() {
139→    document.addEventListener('click', function (e) {
140→      var link = e.target.closest('a[href^="#"]');
141→      if (!link) return;
142→
143→      var targetId = link.getAttribute('href');
144→      // Ignore empty hash links (href="#")
145→      if (targetId === '#' || targetId.length < 2) return;
146→
147→      var targetElement = document.querySelector(targetId);
148→      if (!targetElement) return;
149→
150→      e.preventDefault();
151→
152→      targetElement.scrollIntoView({
153→        behavior: 'smooth',
154→        block: 'start'
155→      });
156→
157→      // Update URL hash without jumping
158→      if (history.pushState) {
159→        history.pushState(null, null, targetId);
160→      }
161→    });
162→  }
163→
164→  initSmoothScroll();
165→
166→
167→  /* ==========================================================================
168→     5. MOBILE BOTTOM SHEET CART
169→     Simple bottom-sheet behavior for .cart-bottom-sheet element.
170→     - Listens for [data-open-cart-sheet] clicks to slide the sheet up.
171→     - Listens for [data-close-cart-sheet] clicks (or overlay tap) to close.
172→     - Adds/removes .cart-bottom-sheet--open class for CSS transitions.
173→  ========================================================================== */
174→
175→  function initBottomSheetCart() {
176→    var sheet = document.querySelector('.cart-bottom-sheet');
177→    if (!sheet) return;
178→
179→    var overlay = sheet.querySelector('.cart-bottom-sheet__overlay');
180→
181→    function openSheet() {
182→      sheet.classList.add('cart-bottom-sheet--open');
183→      document.body.style.overflow = 'hidden'; // Prevent background scroll
184→    }
185→
186→    function closeSheet() {
187→      sheet.classList.remove('cart-bottom-sheet--open');
188→      document.body.style.overflow = '';
189→    }
190→
191→    // Open triggers
192→    document.querySelectorAll('[data-open-cart-sheet]').forEach(function (trigger) {
193→      trigger.addEventListener('click', function (e) {
194→        e.preventDefault();
195→        openSheet();
196→      });
197→    });
198→
199→    // Close triggers (close button inside the sheet)
200→    document.querySelectorAll('[data-close-cart-sheet]').forEach(function (trigger) {
201→      trigger.addEventListener('click', function (e) {
202→        e.preventDefault();
203→        closeSheet();
204→      });
205→    });
206→
207→    // Close when tapping the overlay background
208→    if (overlay) {
209→      overlay.addEventListener('click', closeSheet);
210→    }
211→
212→    // Close on Escape key
213→    document.addEventListener('keydown', function (e) {
214→      if (e.key === 'Escape' && sheet.classList.contains('cart-bottom-sheet--open')) {
215→        closeSheet();
216→      }
217→    });
218→  }
219→
220→  initBottomSheetCart();
221→
222→
223→  /* ==========================================================================
224→     6. SERVICE CARD HOVER - SUBTLE PARALLAX TILT
225→     On desktop, adds a very subtle 3D tilt effect to .glass-card elements
226→     when the mouse moves over them. Max rotation is 2-3 degrees.
227→     Disabled on touch devices to avoid weird behavior.
228→  ========================================================================== */
229→
230→  function initCardTilt() {
231→    // Skip on touch devices (no hover anyway)
232→    if ('ontouchstart' in window || navigator.maxTouchPoints > 0) return;
233→
234→    var cards = document.querySelectorAll('.glass-card');
235→    if (!cards.length) return;
236→
237→    var maxTilt = 3; // Maximum tilt in degrees
238→
239→    cards.forEach(function (card) {
240→      var ticking = false;
241→      var currentX = 0;
242→      var currentY = 0;
243→
244→      card.addEventListener('mousemove', function (e) {
245→        var rect = card.getBoundingClientRect();
246→        // Calculate mouse position relative to card center (-0.5 to 0.5)
247→        currentX = (e.clientX - rect.left) / rect.width - 0.5;
248→        currentY = (e.clientY - rect.top) / rect.height - 0.5;
249→
250→        if (!ticking) {
251→          requestAnimationFrame(function () {
252→            // rotateY for horizontal movement, rotateX for vertical (inverted)
253→            var rotateX = -(currentY * maxTilt * 2);
254→            var rotateY = currentX * maxTilt * 2;
255→            card.style.transform =
256→              'perspective(800px) rotateX(' + rotateX + 'deg) rotateY(' + rotateY + 'deg) scale(1.01)';
257→            ticking = false;
258→          });
259→          ticking = true;
260→        }
261→      });
262→
263→      card.addEventListener('mouseleave', function () {
264→        // Smoothly reset the card to its original position
265→        card.style.transform = 'perspective(800px) rotateX(0deg) rotateY(0deg) scale(1)';
266→      });
267→    });
268→  }
269→
270→  initCardTilt();
271→
272→});
